={{
"You are Study Aura, an educational table generator. Create a structured study table for the topic: " + ($json.body.topic || "General Study") + ". Difficulty: " + ($json.body.difficulty || "easy") + ". Table type: " + ($json.body.tableType || "concept_comparison") + ". Create exactly " + ($json.body.rowCount || 5) + " rows.\n\n" +
"Selected source context:\n" +
(
  Array.isArray($json.body.selectedSources) && $json.body.selectedSources.length > 0
    ? $json.body.selectedSources.map((source, index) => {
        return (index + 1) + ". " + (source.title || "Untitled Source") + " [" + (source.type || "source") + "]\n" +
          "Summary or content: " + (source.summary || source.value || "No summary provided.");
      }).join("\n\n")
    : "No selected sources were provided. Use the topic only."
) +
"\n\nReturn ONLY valid JSON. No markdown. No code fences.\n" +
"Required JSON format: {\"title\": string, \"description\": string, \"columns\": [{\"key\": string, \"label\": string}], \"rows\": [{stringKey: stringValue}]}.\n" +
"Rules:\n" +
"- Use 3 to 5 columns only.\n" +
"- Every row must use the exact column keys.\n" +
"- Keep cell values concise and student-friendly.\n" +
"- Prioritize selected source context when available.\n" +
"- Do not include markdown, comments, or text outside JSON."
}}

parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let table;
let fallback = false;

try {
  table = JSON.parse(cleaned);

  if (!Array.isArray(table.columns) || !Array.isArray(table.rows)) {
    throw new Error("Invalid table format");
  }
} catch (error) {
  fallback = true;
  table = {
    title: "Study Aura Table",
    description: "A quick fallback table for organizing a study topic.",
    columns: [
      { key: "concept", label: "Concept" },
      { key: "meaning", label: "Meaning" },
      { key: "example", label: "Example" }
    ],
    rows: [
      {
        concept: "Key idea",
        meaning: "The main point to understand",
        example: "Break a topic into smaller parts"
      },
      {
        concept: "Review",
        meaning: "Practice remembering important details",
        example: "Use quizzes or flashcards"
      }
    ]
  };
}

let columns = Array.isArray(table.columns) ? table.columns.slice(0, 5) : [];

columns = columns.map((column, index) => {
  const fallbackKey = `column_${index + 1}`;
  const key = String(column.key || fallbackKey).replace(/[^a-zA-Z0-9_]/g, "_").toLowerCase();

  return {
    key,
    label: String(column.label || column.key || `Column ${index + 1}`)
  };
});

if (columns.length < 3) {
  columns = [
    { key: "concept", label: "Concept" },
    { key: "meaning", label: "Meaning" },
    { key: "example", label: "Example" }
  ];
}

const rows = Array.isArray(table.rows)
  ? table.rows.map((row) => {
      const normalizedRow = {};

      for (const column of columns) {
        normalizedRow[column.key] = String(row[column.key] || row[column.label] || "");
      }

      return normalizedRow;
    })
  : [];

return [
  {
    json: {
      table: {
        title: String(table.title || "Study Aura Table"),
        description: String(table.description || "Generated study table."),
        columns,
        rows
      },
      fallback,
      provider: $json.provider || "gemini"
    }
  }
];

